# normalize pubnums (some may have spaces)
uc_set = set([p.strip() for p in uc_pubnums if p])

# helper to parse citation field
def extract_cited_pubnums(citation_field):
    if not citation_field:
        return []
    try:
        cit = json.loads(citation_field)
        res = []
        for c in cit:
            pn = c.get('publication_number')
            if pn:
                res.append(pn.strip())
        return res
    except Exception:
        # try to find patterns
        return re.findall(r"[A-Z]{2}-[0-9][0-9A-Za-z-]+", citation_field)

# helper to extract assignee from Patents_info
def extract_assignee(pi):
    if not pi:
        return None
    # patterns
    patterns = [
        r"([A-Z0-9 &\.\-]{3,}?)\s+holds the", # e.g., 'PANASONIC IP MAN CO LTD holds the'
        r"is assigned to\s+([A-Z0-9 &\.\-]{3,}?)\b",
        r"is owned by\s+([A-Z0-9 &\.\-]{3,}?)\b",
        r"owned by\s+([A-Z0-9 &\.\-]{3,}?)\b",
        r"assigned to\s+([A-Z0-9 &\.\-]{3,}?)\b",
        r"held by\s+([A-Z0-9 &\.\-]{3,}?)\b",
        r"^([A-Z0-9 &\.\-]{3,}?)\s+holds",
    ]
    for pat in patterns:
        m = re.search(pat, pi, re.IGNORECASE)
        if m:
            ass = m.group(1).strip()
            # clean trailing punctuation
            ass = re.sub(r"[\.,;]$", "", ass)
            # uppercase
            ass_up = ass.upper()
            return ass_up
    # fallback: try to find leading uppercase phrase before 'the US patent' etc
    m = re.search(r"^([A-Z0-9 &\.\-]{3,}?)\s+(?:holds|owns|has|files|filed|files the|filed the)", pi)
    if m:
        return m.group(1).strip().upper()
    return None

citing_records = []
for rec in all_recs:
    cited = extract_cited_pubnums(rec.get('citation',''))
    # check intersection
    if any(p in uc_set for p in cited):
        ass = extract_assignee(rec.get('Patents_info',''))
        if not ass:
            # try to find 'by <ASSIGNEE>'
            m = re.search(r"by\s+([A-Z0-9 &\.\-]{3,}?)\b", rec.get('Patents_info',''), re.IGNORECASE)
            if m:
                ass = m.group(1).strip().upper()
        if not ass:
            ass = "UNKNOWN"
        # skip Univ California
        if 'UNIV' in ass and 'CALIFORNIA' in ass:
            continue
        # determine primary CPC code
        primary_code = None
        cpc_field = rec.get('cpc','')
        try:
            cpcs = json.loads(cpc_field)
            for entry in cpcs:
                if entry.get('first'):
                    primary_code = entry.get('code')
                    break
            if not primary_code and len(cpcs)>0:
                primary_code = cpcs[0].get('code')
        except Exception:
            # fallback regex
            codes = re.findall(r"[A-Z]\w{1,2}[0-9][A-Z0-9/]+", cpc_field)
            primary_code = codes[0] if codes else None
        citing_records.append({'rowid': rec.get('rowid'), 'assignee': ass, 'primary_cpc': primary_code})

# deduplicate by rowid
unique = { (r['rowid']): r for r in citing_records }
results = list(unique.values())
# collect unique CPC codes
cpc_codes = sorted(list({r['primary_cpc'] for r in results if r['primary_cpc']}))

output = {'num_citing_records': len(results), 'examples_count': min(20, len(results)), 'citing_records': results, 'cpc_codes': cpc_codes}
print("__RESULT__:")
print(json.dumps(output))"}

